const items = $input.all();
let listaSolicitudes = "📋 *Tus Solicitudes*\n\n";

if (items.length === 0 || !items[0].json.id_ticket) {
  return [{ json: { mensajeFinal: "" } }];
}


for (const item of items) {
  const ticket = item.json.id_ticket || 'N/A';
  const tipo = item.json.tipo || 'N/A';
  const prioridad = item.json.prioridad || 'N/A';
  const descripcion = item.json.descripcion || 'Sin descripción';
  const autor = item.json.creado_por || 'N/A';
  const fecha = item.json.fecha_creacion || 'N/A';

  listaSolicitudes += `🆔 *Ticket:* ${ticket}\n`;
  listaSolicitudes += `📂 *Tipo:* ${tipo}\n`;
  listaSolicitudes += `⚠️ *Prioridad:* ${prioridad}\n`;
  listaSolicitudes += `📝 *Descripción:* ${descripcion}\n`;
  listaSolicitudes += `📅 *Fecha:* ${fecha}\n`;
  listaSolicitudes += `───────────────────\n\n`;
}

return [{ json: { mensajeFinal: listaSolicitudes } }];

var conteoTipo = { "Soporte técnico": 0, "Solicitud administrativa": 0, "Consulta general": 0 };
var conteoPrioridad = { "Alta": 0, "Media": 0, "Baja": 0 };
var conteoEstado = { "Abierto": 0, "En Proceso": 0, "Cerrado": 0 }; 

var datos = items;


if (datos.length === 0 || !datos[0].json.id_ticket) {
  return [{ json: { mensajeEstadisticas: "No hay solicitudes registradas para generar estadísticas." } }];
}


for (var i = 0; i < datos.length; i++) {
  var fila = datos[i].json;


  if (conteoTipo.hasOwnProperty(fila.tipo)) {
    conteoTipo[fila.tipo]++;
  }


  if (conteoPrioridad.hasOwnProperty(fila.prioridad)) {
    conteoPrioridad[fila.prioridad]++;
  }


  if (conteoEstado.hasOwnProperty(fila.estado)) {
    conteoEstado[fila.estado]++;
  }
}


var mensaje = "📊 *Resumen de tus Solicitudes*\n\n";

mensaje += "📂 *Por Tipo:*\n";
mensaje += "• Soporte: " + conteoTipo["Soporte técnico"] + "\n";
mensaje += "• Administrativa: " + conteoTipo["Solicitud administrativa"] + "\n";
mensaje += "• Consulta: " + conteoTipo["Consulta general"] + "\n\n";

mensaje += "⚠️ *Por Prioridad:*\n";
mensaje += "• Alta: " + conteoPrioridad["Alta"] + "\n";
mensaje += "• Media: " + conteoPrioridad["Media"] + "\n";
mensaje += "• Baja: " + conteoPrioridad["Baja"] + "\n\n";

mensaje += "📝 *Por Estado:*\n";
mensaje += "• Abiertos: " + conteoEstado["Abierto"] + "\n";
mensaje += "• En Proceso: " + conteoEstado["En Proceso"] + "\n";
mensaje += "• Cerrados: " + conteoEstado["Cerrado"] + "\n";

return [{
  json: {
    mensajeEstadisticas: mensaje
  }
}];

var filas = items;
var mensaje = "";


if (filas.length === 0 || !filas[0].json.telegram_user) {
  return [{ 
    json: { 
      mensajePerfil: "⚠️ *Error:* No estás registrado en el sistema.\nPor favor, contacta al administrador." 
    } 
  }];
}


var usuario = filas[0].json;

var telegramUser = usuario.telegram_user || "N/A";
var nombreReal = usuario.nombre || "No registrado";
var rolAsignado = usuario.rol || "Sin rol";


mensaje = "👤 *PERFIL DE USUARIO*\n";
mensaje += "───────────────────\n";
mensaje += "🔹 *Telegram:* @" + telegramUser + "\n";
mensaje += "🔹 *Nombre:* " + nombreReal + "\n";
mensaje += "🔹 *Rol:* " + rolAsignado + "\n";
mensaje += "───────────────────";

return [{
  json: {
    mensajePerfil: mensaje,
    datos: {
      user: telegramUser,
      nombre: nombreReal,
      rol: rolAsignado
    }
  }
}];

